#!/usr/bin/env node
// Extract memory values from an ELF binary's loadable segments.
// Maps each PT_LOAD segment at load base 0x400000 + p_vaddr and reads
// 4-byte little-endian words at word-aligned addresses.

const fs = require('fs');

const path = process.argv[2];
if (!path) {
  process.stderr.write('usage: node extract.js <binary>\n');
  process.exit(1);
}

const b = fs.readFileSync(path);

// ELF64 header fields
if (!(b[0] === 0x7f && b[1] === 0x45 && b[2] === 0x4c && b[3] === 0x46)) {
  process.stderr.write('not an ELF file\n');
  process.exit(1);
}

const phoff = Number(b.readBigUInt64LE(0x20));
const phentsize = b.readUInt16LE(0x36);
const phnum = b.readUInt16LE(0x38);

const PT_LOAD = 1;
const BASE = 0x400000; // load bias for the PIE image

const out = {};

for (let i = 0; i < phnum; i++) {
  const o = phoff + i * phentsize;
  const type = b.readUInt32LE(o);
  if (type !== PT_LOAD) continue;

  const off = Number(b.readBigUInt64LE(o + 8));
  const vaddr = Number(b.readBigUInt64LE(o + 16));
  const filesz = Number(b.readBigUInt64LE(o + 32));

  for (let k = 0; k + 4 <= filesz; k += 4) {
    const addr = BASE + vaddr + k;
    if (addr % 4 !== 0) continue;
    const v = b.readUInt32LE(off + k);
    // Emit only values whose interpretation is identical for signed and
    // unsigned 32-bit reads, so the output is agnostic to that choice.
    if (v >= 0x80000000) continue;
    out[addr] = v;
  }
}

process.stdout.write(JSON.stringify(out));

